tests.testString:
({
  test: () => runPython(`
  _msg = 'Only Movie or TVSeries instances can be added'
  _expected_error = f"Expected to raise 'MediaError: {_msg}'"
  _c = MediaCatalogue()
  try:    
    _c.add("Not a movie")
  except MediaError as e:
    assert str(e) == _msg
  else:
    assert False, _expected_error

  try:
    _c.add({})
  except MediaError as e:
    assert str(e) == _msg
  else:
    assert False, _expected_error
  `)
})

